// frontend/src/components/Navbar/Navbar.js
import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

// Menambahkan userRole ke dalam props agar tidak terjadi error no-undef
const Navbar = ({ activeMenu, setActiveMenu, isAuthenticated, userRole, handleLogout }) => {
    const navigate = useNavigate();
    const [isOpen, setIsOpen] = useState(false);

    // State untuk melacak elemen mana yang sedang di-hover
    const [hoveredMenu, setHoveredMenu] = useState(null);

    const navigateTo = (path, menuId) => {
        if (setActiveMenu) setActiveMenu(menuId);
        navigate(path);
        setIsOpen(false);
    };

    return (
        <nav style={{ 
            display: 'flex', 
            justifyContent: 'space-between', 
            alignItems: 'center', 
            padding: '20px 5%', 
            background: '#0c0a09', 
            borderBottom: '1px solid #262626',
            position: 'relative'
        }}>
            {/* Logo */}
            <div onClick={() => navigateTo('/', 'home')} style={{ cursor: 'pointer' }}>
                <h3 style={{ color: '#fef3c7', margin: 0 }}>PasukanYerusSolo</h3>
            </div>

            {/* Menu Navigasi */}
            <div className="nav-menu" style={{ display: 'flex', gap: '20px', alignItems: 'center' }}>
                {/* Menu Khusus Role HRD */}
                {isAuthenticated && userRole === 'hrd' && (
                    <button onClick={() => navigate('/hrd/dashboard')} style={{ background: 'none', border: 'none', color: '#fff', cursor: 'pointer', fontWeight: '700', fontSize: '14px' }}>
                        Dashboard HRD
                    </button>
                )}

                {isAuthenticated ? (
                    <button 
                        onClick={handleLogout}
                        style={{ 
                            background: 'transparent', border: '1px solid #ef4444',
                            color: hoveredMenu === 'logout' ? '#fff' : '#ef4444', 
                            fontWeight: '700', fontSize: '12px', cursor: 'pointer', transition: '0.3s',
                            padding: '6px 16px', borderRadius: '20px'
                        }}
                        onMouseEnter={() => setHoveredMenu('logout')}
                        onMouseLeave={() => setHoveredMenu(null)}
                    >Keluar</button>
                ) : (
                    <button 
                        onClick={() => navigate('/login')} 
                        style={{ 
                            padding: '6px 16px', borderRadius: '20px', 
                            border: '1px solid #ea580c', 
                            background: hoveredMenu === 'login' ? '#ea580c' : 'transparent', 
                            color: hoveredMenu === 'login' ? '#fff' : '#ea580c', 
                            fontWeight: '700', fontSize: '12px', cursor: 'pointer', transition: '0.3s' 
                        }}
                        onMouseEnter={() => setHoveredMenu('login')}
                        onMouseLeave={() => setHoveredMenu(null)}
                    >Login</button>
                )}
            </div>

            {/* Gaya Hamburger Menu */}
            <style>{`
                @media (max-width: 768px) {
                    .nav-menu { display: none !important; }
                }
            `}</style>
        </nav>
    );
};

export default Navbar;
